    {
        emulator.data = (byte)(emulator.data - 0x01 & 0b11111111);
        emulator.P &= 0x5C;
        if (emulator.A >= emulator.data)
        {
            emulator.P |= 0x01;
        }

        var result = emulator.A - emulator.data;
        if (result == 0)
        {
            emulator.P |= 0x02;
        }

        if (((result & 0b10000000) != 0x00))
        {
            emulator.P |= 0x80;
        }

        // Queue overlap step.
        emulator.overlapPipeline = &Overlap2;
    }

